import os
import sys
import subprocess
from pathlib import Path
from zipfile import ZipFile, ZIP_DEFLATED

ROOT = Path(__file__).resolve().parent
REQ = ROOT / "requirements.txt"
DIST = ROOT / "dist"
PACKAGE_NAME = "deployment_package.zip"


def run(cmd, check=True):
    print(f"+ {' '.join(cmd)}")
    return subprocess.run(cmd, cwd=ROOT, check=check)


def install_dependencies():
    if not REQ.exists():
        raise FileNotFoundError("requirements.txt not found")
    run([sys.executable, "-m", "pip", "install", "--upgrade", "pip"])
    run([sys.executable, "-m", "pip", "install", "-r", str(REQ)])


def run_tests():
    test_dir = ROOT / "tests"
    if test_dir.exists():
        run([sys.executable, "-m", "pytest", "-q"])
    else:
        print("No tests directory found; skipping tests.")


def package_deployment():
    DIST.mkdir(exist_ok=True)
    package_path = DIST / PACKAGE_NAME

    exclude_dirs = {
        ".git",
        "__pycache__",
        ".pytest_cache",
        ".mypy_cache",
        "dist",
        "build",
        ".venv",
        "venv",
        "env",
    }

    exclude_files = {
        package_path.name,
    }

    with ZipFile(package_path, "w", compression=ZIP_DEFLATED) as zf:
        for path in ROOT.rglob("*"):
            rel = path.relative_to(ROOT)

            if any(part in exclude_dirs for part in rel.parts):
                continue
            if path.is_file() and path.name not in exclude_files:
                zf.write(path, rel.as_posix())

    print(f"Created package: {package_path}")


def main():
    install_dependencies()
    run_tests()
    package_deployment()
    print("Deployment workflow completed successfully.")


if __name__ == "__main__":
    try:
        main()
    except subprocess.CalledProcessError as exc:
        sys.exit(exc.returncode)
    except Exception as exc:
        print(f"Error: {exc}", file=sys.stderr)
        sys.exit(1)